func TestMiiData(t *testing.T) {
	for i, tc := range miiData {
		t.Run(fmt.Sprintf("case %d", i), func(t *testing.T) {
			buffer := make([]byte, MiiBlockOffset+len(tc.raw))
			copy(buffer[MiiBlockOffset:], tc.raw)
			r := bytes.NewReader(buffer)

			block, err := ReadMiiBlock(r)
			if !errors.Is(err, tc.err) {
				t.Fatalf("expected err %v, got %v", tc.err, err)
			}
			if tc.err != nil {
				return
			}
			var got []string
			for slot := range block.MiiSlotSeq() {
				mii := DecodeMii(slot)
				if mii.Name != "" {
					got = append(got, mii.Name)
				}
			}
			if !slices.Equal(got, tc.result) {
				t.Fatalf("mismatch\nexp: %+v\ngot: %+v", tc.result, got)
			}
		})
	}
}
